#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    const long long P = 1LL<<27; // 134217728
    const long long Q = 1LL<<28; // 268435456
    while(T--){
        long long X; scanf("%lld", &X);
        long long A = X;
        long long B = X + P;
        long long C = X + Q;
        printf("%lld %lld %lld\n", A, B, C);
    }
    return 0;
}

